#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    int N, M, L;
    std::cin >> N >> M >> L;
    std::vector<std::pair<int, int>> main_dishes(N), sides(M);
    for (int i = 0; i < N; ++i) std::cin >> main_dishes[i].first >> main_dishes[i].second;
    for (int i = 0; i < M; ++i) std::cin >> sides[i].first >> sides[i].second;

    std::vector<int> dp(L + 1, 0);
    for (auto [cost, score] : sides) {
        for (int w = L; w >= cost; --w) {
            dp[w] = std::max(dp[w], dp[w - cost] + score);
        }
    }

    int answer = 0;
    for (auto [cost, score] : main_dishes) {
        if (cost <= L) answer = std::max(answer, score + dp[L - cost]);
    }
    std::cout << answer << '\n';
    return 0;
}

