int main() {
    int H, W, K;
    std::cin >> H >> W >> K;
    int capacity = ((H + 1) / 2) * ((W + 1) / 2);
    if (K > capacity) {
        std::cout << "IMPOSSIBLE\n";
        return 0;
    }
    std::vector<std::string> grid(H, std::string(W, '.'));
    for (int i = 0; i < H && K > 0; i += 2) {
        for (int j = 0; j < W && K > 0; j += 2) {
            grid[i][j] = '#';
            --K;
        }
    }
    for (const std::string& row : grid) std::cout << row << '\n';
    return 0;
}

