#include <iomanip>
#include <iostream>

int main() {
    int n;
    std::cin >> n;
    long long first = 0, last = 0;
    for (int i = 0; i < n; ++i) {
        long long x;
        std::cin >> x;
        if (i == 0) first = x;
        if (i == n - 1) last = x;
    }
    long long diff = last - first;
    long long denom = n - 1;
    if (diff % denom == 0) {
        std::cout << diff / denom << '\n';
    } else {
        double ans = static_cast<double>(diff) / static_cast<double>(denom);
        std::cout << std::fixed << std::setprecision(3) << ans << '\n';
    }
    return 0;
}

