int main() {
    std::string S;
    std::getline(std::cin, S);
    std::set<std::string> users;
    for (std::size_t i = 0; i < S.size(); ++i) {
        if (S[i] != '@') continue;
        std::size_t j = i + 1;
        std::string name;
        while (j < S.size() && S[j] >= 'a' && S[j] <= 'z') {
            name.push_back(S[j]);
            ++j;
        }
        if (!name.empty()) users.insert(name);
    }
    for (const std::string& name : users) std::cout << name << '\n';
    return 0;
}

