int main() {
    int a, b;
    std::cin >> a >> b;
    std::vector<char> state(10, 'x');
    for (int i = 0; i < a; ++i) {
        int p;
        std::cin >> p;
        state[p] = '.';
    }
    for (int i = 0; i < b; ++i) {
        int q;
        std::cin >> q;
        state[q] = 'o';
    }

    auto print_row = [&](const std::vector<int>& pins, int leading) {
        for (int i = 0; i < leading; ++i) std::cout << ' ';
        for (std::size_t i = 0; i < pins.size(); ++i) {
            if (i > 0) std::cout << ' ';
            std::cout << state[pins[i]];
        }
        std::cout << '\n';
    };

    print_row({7, 8, 9, 0}, 0);
    print_row({4, 5, 6}, 1);
    print_row({2, 3}, 2);
    print_row({1}, 3);
    return 0;
}

