#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    int N;
    long long T;
    std::cin >> N >> T;
    long long total = 0;
    std::vector<long long> reduce(N);
    for (int i = 0; i < N; ++i) {
        long long A, B;
        std::cin >> A >> B;
        total += A;
        reduce[i] = A - B;
    }
    if (total <= T) {
        std::cout << 0 << '\n';
        return 0;
    }
    std::sort(reduce.rbegin(), reduce.rend());
    for (int i = 0; i < N; ++i) {
        total -= reduce[i];
        if (total <= T) {
            std::cout << i + 1 << '\n';
            return 0;
        }
    }
    std::cout << -1 << '\n';
    return 0;
}

